mapper.select:
SELECT e.EMPNO , e.NAME , e.LEVELNO , e.CLASSNO , e.MAILNO , e.INTELNO , e.HOSTNAME , e.NOTREMOVE , e.EMP_ORDER , e.DOWNLOAD , e.LEVELDATE , e.TITLE , e.EXIST , e.IPADDR , e.M_COUNT , e.EXFAXNO , e.MOBILE_PHN , e.JIKGUB_NAME , e.VPN_YN , e.USER_GUBUN , e.DEPTNO , e.EXTELNO , d.DEPT_NAME , d.DEPT_GUBUN FROM EMPLOYEE e INNER JOIN DEPT d ON e.DEPTNO = d.DEPTNO WHERE 1 = 1
AND e.EMPNO = #{empno}
AND e.DEPTNO = #{deptno}
AND e.NAME LIKE '%' || #{name} || '%'
AND (e.EXIST IS NULL OR e.EXIST != '30') -- 퇴직자 ORDER BY e.DEPTNO, e.EMPNO

mapper.insert:
INSERT INTO EMPLOYEE
	 ( EMPNO, LEVELNO, CLASSNO, MAILNO, NAME
	 , INTELNO, HOSTNAME, NOTREMOVE, EMP_ORDER, DOWNLOAD
	 , LEVELDATE, TITLE, EXIST, IPADDR, M_COUNT
	 , EXFAXNO, MOBILE_PHN, JIKGUB_NAME, VPN_YN, USER_GUBUN
	 , DEPTNO, EXTELNO, REG_DATE
	 )
VALUES
	 ( #{empno}, #{levelno}, #{classno}, #{mailno}, #{name}
	 , #{intelno}, #{hostname}, 0, 0, 0
	 , #{leveldate}, #{title}, #{exist}, #{ipaddr}, #{mCount}
	 , #{exfaxno}, #{mobilePhn}, #{jikgubName}, #{vpnYn}, #{userGubun}
	 , #{deptno}, #{extelno}, SYSDATE
	 )
